# Enable FIDO2 passwordless sign-in via Authentication Methods Policy
import requests

TENANT_ID = "YOUR_TENANT_ID"

def get_token():
    r = requests.post(
        f"https://login.microsoftonline.com/{TENANT_ID}/oauth2/v2.0/token",
        data={
            "grant_type": "client_credentials",
            "client_id": "YOUR_APP_ID",
            "client_secret": "YOUR_SECRET",
            "scope": "https://graph.microsoft.com/.default",
        }
    )
    return r.json()["access_token"]

token = get_token()
headers = {"Authorization": f"Bearer {token}", "Content-Type": "application/json"}

# Enable FIDO2 for all users with attestation enforcement disabled
fido2_config = {
    "state": "enabled",
    "isSelfServiceRegistrationAllowed": True,
    "isAttestationEnforced": False,      # True = only FIDO2 keys from approved vendors
    "includeTargets": [
        {"targetType": "group", "id": "all_users"}
    ],
    "excludeTargets": [],
    "keyRestrictions": {
        "isEnforced": False,
        "enforcementType": "allow",
        "aaGuids": []
        # aaGuids to restrict to specific vendors:
        # YubiKey 5 (USB-A): ee882879-721c-4f3d-ab35-32b6527d55ae
        # YubiKey 5 (NFC):   2fc0579f-8113-47ea-b116-bb5a8db9202a
        # Microsoft passkey: 90a3ccdf-635c-4729-a248-9b709135078f
    }
}

resp = requests.patch(
    "https://graph.microsoft.com/v1.0/policies/authenticationMethodsPolicy"
    "/authenticationMethodConfigurations/Fido2",
    headers=headers,
    json=fido2_config
)
print(f"FIDO2 enabled: {resp.status_code}")

# Enable Microsoft Authenticator passwordless phone sign-in
authenticator_config = {
    "state": "enabled",
    "isSoftwareOathEnabled": False,   # separate from passwordless phone sign-in
    "featureSettings": {
        "numberMatchingRequiredState": {
            "state": "enabled",
            "includeTarget": {"targetType": "group", "id": "all_users"}
        },
        "displayAppInformationRequiredState": {
            "state": "enabled",
            "includeTarget": {"targetType": "group", "id": "all_users"}
        }
    },
    "includeTargets": [
        {
            "targetType": "group",
            "id": "all_users",
            "authenticationMode": "any"   # "any" = MFA or passwordless; "deviceBasedPush" = passwordless only
        }
    ]
}
resp = requests.patch(
    "https://graph.microsoft.com/v1.0/policies/authenticationMethodsPolicy"
    "/authenticationMethodConfigurations/MicrosoftAuthenticator",
    headers=headers,
    json=authenticator_config
)
print(f"Authenticator passwordless enabled: {resp.status_code}")

# CA policy: allow passwordless users to skip MFA step (passwordless IS MFA)
# When a user signs in with FIDO2 or WHfB, the sign-in already satisfies MFA
# You still need a CA policy that requires MFA — passwordless methods satisfy it automatically

import requests

token = get_token()
headers = {"Authorization": f"Bearer {token}", "Content-Type": "application/json"}

# Get the "Phishing-resistant MFA" built-in authentication strength
strengths = requests.get(
    "https://graph.microsoft.com/v1.0/identity/conditionalAccess/authenticationStrength/policies",
    headers=headers
).json().get("value", [])

phishing_resistant = next((s for s in strengths if s["displayName"] == "Phishing-resistant MFA"), None)
mfa_strength = next((s for s in strengths if s["displayName"] == "Multifactor authentication"), None)

# Policy 1: require phishing-resistant MFA for admin portals
admin_policy = {
    "displayName": "Require Phishing-Resistant MFA — Azure Admin Portals",
    "state": "enabled",
    "conditions": {
        "users": {
            "includeUsers": ["All"],
            "excludeGroups": ["BREAK-GLASS-ID"]
        },
        "applications": {
            # Azure portal, Entra admin center, Intune portal, etc.
            "includeApplications": [
                "797f4846-ba00-4fd7-ba43-dac1f8f63013",  # Azure portal
                "c44b4083-3bb0-49c1-b47d-974e53cbdf3c",  # Entra admin center
            ]
        }
    },
    "grantControls": {
        "operator": "OR",
        "authenticationStrength": {"id": phishing_resistant["id"]}
    }
}

resp = requests.post(
    "https://graph.microsoft.com/v1.0/identity/conditionalAccess/policies",
    headers=headers,
    json=admin_policy
)
print(f"Admin portal policy: {resp.status_code} {resp.json().get('id')}")

# Policy 2: standard workforce can use any MFA (passwordless or traditional)
workforce_policy = {
    "displayName": "Require MFA — Workforce All Apps",
    "state": "enabled",
    "conditions": {
        "users": {"includeUsers": ["All"], "excludeGroups": ["BREAK-GLASS-ID"]},
        "applications": {"includeApplications": ["All"]}
    },
    "grantControls": {
        "operator": "OR",
        "authenticationStrength": {"id": mfa_strength["id"]}
        # FIDO2, WHfB, Authenticator push — all satisfy "Multifactor authentication" strength
    }
}
requests.post(
    "https://graph.microsoft.com/v1.0/identity/conditionalAccess/policies",
    headers=headers, json=workforce_policy
)
